use anyhow::Result;use burn::{backend::{wgpu::WgpuDevice,Wgpu},tensor::{Distribution,Tensor}};use clap::Parser;use std::{fs,path::PathBuf};use video_contract::StudentSpec;use video_student::BrowserVideoStudent;
#[derive(Parser)]struct Args{#[arg(long)]spec:PathBuf,#[arg(long,default_value_t=4)]frames:usize,#[arg(long,default_value_t=32)]height:usize,#[arg(long,default_value_t=48)]width:usize}
fn main()->Result<()>{let a=Args::parse();let spec:StudentSpec=serde_json::from_slice(&fs::read(a.spec)?)?;spec.validate()?;let device=WgpuDevice::default();let model=BrowserVideoStudent::<Wgpu>::new(spec.clone(),&device);let latents=Tensor::<Wgpu,5>::random([1,spec.latent_channels,a.frames,a.height,a.width],Distribution::Normal(0.0,1.0),&device);let timestep=Tensor::<Wgpu,2>::zeros([1,1],&device);let prompt=Tensor::<Wgpu,3>::zeros([1,8,spec.text_width],&device);let(output,_)=model.forward(latents,timestep,prompt);println!("native WGPU inference complete: {:?}",output.dims());Ok(())}
